// Counter using a closure
function makeCounter(start = 0) {
  let count = start; // private variable
  return {
    increment() { return ++count; },
    decrement() { return --count; },
    value()     { return count; }
  };
}

const counter = makeCounter(10);
console.log(counter.increment()); // 11
console.log(counter.increment()); // 12
console.log(counter.decrement()); // 11
// count is inaccessible from outside — only via counter methods

// Classic loop closure bug (var) and fix (let)
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 100); // 3 3 3 (bug)
}
for (let j = 0; j < 3; j++) {
  setTimeout(() => console.log(j), 100); // 0 1 2 (correct)
}
